fn b_add(_: &mut Evaluator,a:&[Value])->Result<Value>{fold_num(a,Value::Int(0),add2)} fn b_mul(_: &mut Evaluator,a:&[Value])->Result<Value>{fold_num(a,Value::Int(1),mul2)}
fn b_sub(_: &mut Evaluator,a:&[Value])->Result<Value>{ if a.len()==1{sub2(Value::Int(0),a[0].clone())}else{fold_num(&a[1..],a[0].clone(),sub2)} }
fn b_div(_: &mut Evaluator,a:&[Value])->Result<Value>{ let r=if a.len()==1{div2(Value::Int(1),a[0].clone())}else{fold_num(&a[1..],a[0].clone(),div2)}; r.map_err(|e|if e.tag=="division-by-zero" && a.len()>=2{SchemeError::new("division-by-zero",vec![Value::string("~A: division by zero, (~A ~S ~S)"),Value::symbol("/"),Value::symbol("/"),a[0].clone(),a[1].clone()])}else{e}) }
fn b_eqnum(_: &mut Evaluator,a:&[Value])->Result<Value>{cmp(a,|x,y|x==y)} fn b_lt(_: &mut Evaluator,a:&[Value])->Result<Value>{cmp(a,|x,y|x<y)} fn b_gt(_: &mut Evaluator,a:&[Value])->Result<Value>{cmp(a,|x,y|x>y)} fn b_le(_: &mut Evaluator,a:&[Value])->Result<Value>{cmp(a,|x,y|x<=y)} fn b_ge(_: &mut Evaluator,a:&[Value])->Result<Value>{cmp(a,|x,y|x>=y)}
fn round_even(x:f64)->i64{let fl=x.floor(); let frac=x-fl; if (frac-0.5).abs()<1e-12 { if (fl as i64)%2==0 {fl as i64}else{fl as i64+1} } else { x.round() as i64 }}
fn b_magnitude(_: &mut Evaluator,a:&[Value])->Result<Value>{let (r,i)=to_complex(&a[0])?; let m=(r*r+i*i).sqrt(); if matches!(a[0],Value::Int(_)) && i==0.0 { Ok(Value::Int(m as i64)) } else { Ok(Value::Float(m)) }} fn b_angle(_: &mut Evaluator,a:&[Value])->Result<Value>{let (r,i)=to_complex(&a[0])?; Ok(Value::Float(i.atan2(r)))} fn b_real_part(_: &mut Evaluator,a:&[Value])->Result<Value>{match a[0]{Value::Complex(r,_)=>Ok(Value::Float(r)),_=>Ok(a[0].clone())}} fn b_imag_part(_: &mut Evaluator,a:&[Value])->Result<Value>{match a[0]{Value::Complex(_,i)=>Ok(Value::Float(i)),_=>Ok(Value::Int(0))}} fn b_exp(_: &mut Evaluator,a:&[Value])->Result<Value>{let (r,i)=to_complex(&a[0])?; if i==0.0{Ok(Value::Float(r.exp()))}else{let er=r.exp(); Ok(Value::Complex(er*i.cos(),er*i.sin()))}} fn b_log(_: &mut Evaluator,a:&[Value])->Result<Value>{let (r,i)=to_complex(&a[0])?; if i==0.0{if r==0.0{Ok(Value::Complex(f64::NEG_INFINITY,std::f64::consts::PI))}else{Ok(Value::Float(r.ln()))}}else{Ok(Value::Complex((r*r+i*i).sqrt().ln(),i.atan2(r)))}} fn b_tan(_: &mut Evaluator,a:&[Value])->Result<Value>{Ok(Value::Float(as_f64(&a[0])?.tan()))}
fn b_min(_: &mut Evaluator,a:&[Value])->Result<Value>{if a.iter().all(|v|matches!(v,Value::Int(_))){return Ok(Value::Int(a.iter().map(as_i64).collect::<Result<Vec<_>>>()?.into_iter().min().unwrap()));} let m=a.iter().map(as_f64).collect::<Result<Vec<_>>>()?.into_iter().fold(f64::INFINITY,f64::min); Ok(Value::Float(m))}
fn b_max(_: &mut Evaluator,a:&[Value])->Result<Value>{if a.iter().all(|v|matches!(v,Value::Int(_))){return Ok(Value::Int(a.iter().map(as_i64).collect::<Result<Vec<_>>>()?.into_iter().max().unwrap()));} let m=a.iter().map(as_f64).collect::<Result<Vec<_>>>()?.into_iter().fold(f64::NEG_INFINITY,f64::max); Ok(Value::Float(m))}
fn b_zerop(_: &mut Evaluator,a:&[Value])->Result<Value>{Ok(Value::Bool(as_f64(&a[0])?==0.0))}
fn b_nanp(_: &mut Evaluator,a:&[Value])->Result<Value>{Ok(Value::Bool(as_f64(&a[0]).map(|x|x.is_nan()).unwrap_or(false)))}
fn b_positivep(_: &mut Evaluator,a:&[Value])->Result<Value>{Ok(Value::Bool(as_f64(&a[0])?>0.0))}
fn b_negativep(_: &mut Evaluator,a:&[Value])->Result<Value>{Ok(Value::Bool(as_f64(&a[0])?<0.0))}
fn b_evenp(_: &mut Evaluator,a:&[Value])->Result<Value>{Ok(Value::Bool(as_i64(&a[0])?%2==0))}
fn b_oddp(_: &mut Evaluator,a:&[Value])->Result<Value>{Ok(Value::Bool(as_i64(&a[0])?%2!=0))}

fn value_kind(v:&Value)->&'static str{match v{Value::Symbol(_)=>"a symbol",Value::Float(_)=>"a real",Value::Rational(_,_)=>"a ratio",Value::Int(_)=>"an integer",Value::Nil=>"nil",Value::Char(_)|Value::NamedChar(_)=>"a character",_=>"an object"}}
fn strict_int_arg(v:&Value, who:&str, pos:i64, expected:&str)->Result<i64>{match v{Value::Int(n)=>Ok(*n),_=>Err(SchemeError::new("wrong-type-arg",vec![Value::string("~A ~:D argument, ~S, is ~A but should be ~A"),Value::symbol(who),Value::Int(pos),v.clone(),Value::string(value_kind(v)),Value::string(expected)]))}}
fn strict_usize_arg(v:Option<&Value>, who:&str, pos:i64, expected:&str)->Result<usize>{let v=v.ok_or_else(||SchemeError::new("wrong-number-of-args",vec![]))?; let n=strict_int_arg(v,who,pos,expected)?; if n<0{return Err(SchemeError::new("out-of-range",vec![Value::string("~A ~:D argument, ~S, is out of range (~A)"),Value::symbol(who),Value::Int(pos),Value::Int(n),Value::string("it is negative")]))} Ok(n as usize)}
